Action.ExecScriptExpression:
using System;
using System.Drawing;
using System.Linq;
using System.Threading;
using System.Windows.Forms;
using Triggernometry.Core;
using Triggernometry.PluginBridges;
using Triggernometry.UI.CustomControls;
using Triggernometry.UI.Forms;
using static Triggernometry.UI.Forms.GameConfigForm;

RealPlugin.Instance.RegisterNamedCallback(U7bEntry.Info.ConfigName, new Action<object, string>((_, __) => U7bEntry.Start()), null);

public static class U7bEntry
{
    public static ConfigInfo Info = new ConfigInfo("绝妖星宝宝椅", "${env:version}", "阿洛", "${env:prefix}_cfg");
    static Color Blue = Color.FromArgb(0x22, 0x66, 0xff);
    public static void RunConfigForm()
    {
        try { _RunConfigForm(); }
        catch (Exception ex)
        {
            MessageBox.Show("配置界面运行时遇到问题：\n\n" + ex, Info.Name, MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
    }

    private static void _RunConfigForm()
    {
        GameConfigForm form = new GameConfigForm(Info);
        form.Shown += (sender, e) => RealPlugin.Instance.InvokeNamedCallback("command", "/e <se.9>");

        BijectDictionary<string, string> cbxItems;
        Option optionCtrl;
        Label label;
        string hint = "";

        #region 配置：特效

        OptionsTableLayoutPanel tableVfx = form.AddOptionGroup(" 特效 ");

        hint = "仅在单独出现时绘制，以防习惯性去空白地板；\n冰雷组合技不会绘制，而是直接标记安全区。";
        optionCtrl = new OptionChk("　[真假冰/雷] 单独出现时绘制危险区", "冰雷_bOmen", true, hint);
        form.AddOption(optionCtrl, tableVfx);

        hint = "根据 Boss 位置拟合计算，站在月环内可保证不会击退到场外。";
        optionCtrl = new OptionChk("　[P3 击退] 以月环绘制击退危险范围", "P3击退_月环_bOmen", true, hint);
        form.AddOption(optionCtrl, tableVfx);

        hint = "在每个黑洞下方绘制实际危险区。";
        optionCtrl = new OptionChk("　[P3 黑洞] 绘制黑洞危险区", "P3黑洞_bOmen", true, hint);
        form.AddOption(optionCtrl, tableVfx);

        hint = "缩小场内不可能有连线的八个黑洞。\n不建议在关闭黑洞危险区时开启此选项。";
        optionCtrl = new OptionChk("　[P3 黑洞] 缩小场内黑洞", "P3黑洞_bScaling", true, hint);
        form.AddOption(optionCtrl, tableVfx);

        hint = "沿地火前进方向画出白色辅助线，两个方向辅助线交点即为备选安全点。";
        optionCtrl = new OptionChk("　[P5 地火] 开启斜向辅助线", "P5地火_辅助线_bOmen", true, hint);
        form.AddOption(optionCtrl, tableVfx);

        cbxItems = new BijectDictionary<string, string>(
            ("0", " 0（禁用）"),
            ("0.5", " 0.5"),
            ("1.0", " 1.0"),
            ("1.5", " 1.5"),
            ("2.0", " 2.0")
        );
        hint = "加深中心紫圈边缘的紫色，防止紫圈与目标圈重合而看不清危险区。\n数值越大效果越明显。";
        optionCtrl = new OptionCbx("　[P5 软狂暴] 中心紫圈高亮特效的深度", "P5软狂暴_中心紫圈α", cbxItems, "1.0", hint);
        form.AddOption(optionCtrl, tableVfx);

        #endregion 配置：特效

        #region 配置：P5

        OptionsTableLayoutPanel tableP5 = form.AddOptionGroup(" P5 ");

        cbxItems = new BijectDictionary<string, string>(
            ("0,14,4,8,6,10,2,12", " 绝伊甸 P1 雾龙站位（正八方）"),
            ("1,15,5,11,7,9,3,13", " 绝欧米茄 P1 分散站位（斜八方）")
        );
        hint = "绝伊甸站位：正北逆时针 MT D3 H1 D1 H2 D2 D4 ST\n绝欧米茄站位：正北逆时针 MT D3 H1 D1 D2 H2 D4 ST";
        optionCtrl = new OptionCbx("　[癫狂] 八方站位", "P5癫狂_pIdx至dir16", cbxItems, "0,14,4,8,6,10,2,12", hint);
        form.AddOption(optionCtrl, tableP5);

        cbxItems = new BijectDictionary<string, string>(
            ("同色顺", " 去火塔顺时针方向"),
            ("同色逆", " 去火塔逆时针方向"),
            ("火雷冰", " 固定找雷"),
            ("火冰雷", " 固定找冰")
        );
        optionCtrl = new OptionCbx("　[三星] 火易伤组首轮找塔方式", "P5三星_易伤strat", cbxItems, "同色顺");
        form.AddOption(optionCtrl, tableP5);

        cbxItems = new BijectDictionary<string, string>(
            ("1", " 偏顺时针 / 面向场外偏右"),
            ("0", " 偏逆时针 / 面向场外偏左")
        );
        hint = "二者中偏顺时针的塔 = 从正北逆时针开始找的第一座双塔，反之同理";
        optionCtrl = new OptionCbx("　[三星] 闲人组踩同色双塔中哪一个", "P5三星_闲人b偏顺", cbxItems, "1", hint);
        form.AddOption(optionCtrl, tableP5);

        cbxItems = new BijectDictionary<string, string>(
            ("自动", " 按照职能自动分配"),
            ("中", " 中心 ○"),
            ("上", " 正上 ↑"),
            ("下", " 正下 ↓"),
            ("左", " 正左 ←"),
            ("右", " 正右 →"),
            ("左上", " 左上 ↖"),
            ("右上", " 右上 ↗"),
            ("左下", " 左下 ↙"),
            ("右下", " 右下 ↘"),
            ("无", " 禁用指路")
        );
        hint = "此选项代表两步法地火会使用到的四个格点的位置。\n\n" +
            "默认按职能分配不同站位，以防多人挤在一起难以分散：\n" +
            "· T/近战：中心（目标圈内四个格点）\n" +
            "· D3：正上（目标圈偏北四个格点）\n" +
            "· D4：正下（目标圈偏南四个格点）\n" +
            "· H1: 正左（目标圈偏西四个格点）\n" +
            "· H2: 正右（目标圈偏东四个格点）\n" +
            "其中 MT ST D1 D2 最终分别去目标圈内上下左右；远程在自己方向上出去分散。\n\n" +
            "你也可以选择起跑点，覆盖默认选项。\n" +
            "其中四个斜方向完全不与中心重合，可完全避免分散冲突；\n" +
            "但外侧两个点比较靠近场边，请自行取舍。";
        optionCtrl = new OptionCbx("　[地火] 两步指路选用的大致方向（详见悬停说明）", "P5地火_方向", cbxItems, "自动", hint);
        form.AddOption(optionCtrl, tableP5);

        #endregion 配置：P5

        #region 配置：P3

        OptionsTableLayoutPanel tableP3 = form.AddOptionGroup(" P3 ");

        hint = @"仅会在以下三种情况下自动切换目标：
· 刚获取决战 debuff 时选择的是错误的 Boss；
· 对错误的 Boss 产生了单体伤害；
· 从非 Boss 目标（如未选中目标或选中玩家）切换至错误 Boss。

不会阻止从正确的 Boss 切换目标至另一个 Boss。";
        optionCtrl = new OptionChk("　[防火墙] 启用目标自动切换", "P3防火墙_b切目标", true, hint);
        form.AddOption(optionCtrl, tableP3);

        hint = @"播报频道为配置中的“公开频道”。\n这不意味着此频道必须公开可见，你可以将公开频道设为默语。";
        optionCtrl = new OptionChk("　[防火墙] 文本播报队友打到无敌目标", "P3防火墙_b播报队友", true, hint);
        form.AddOption(optionCtrl, tableP3);

        cbxItems = new BijectDictionary<string, string>(
            ("正攻", " 正攻（盗火）"),
            ("逃课火", " 逃课（全员火法阵集合）")
        );
        optionCtrl = new OptionCbx("　[一运] 水火风机制解法", "P3一运_strat", cbxItems, "逃课火");
        form.AddOption(optionCtrl, tableP3);

        cbxItems = new BijectDictionary<string, string>(
            ("跟随", " 跟随第二轮转向"),
            ("顺", " 固定偏顺时针"),
            ("逆", " 固定偏逆时针")
        );
        hint = "去自己麻将点名所对应的直条分身的正对面后，需要偏 22.5°（即去正斜点之间），选择此偏转方向的确定方式。";
        optionCtrl = new OptionCbx("　[麻将] 引导位置偏向", "P3麻将_偏向", cbxItems, "跟随", hint);
        form.AddOption(optionCtrl, tableP3);

        cbxItems = new BijectDictionary<string, string>(
            ("固定", " 固定式（1 无污泥 TH，2 无污泥 D，3 污泥）"),
            ("1,2,3,4,5,6,7,8", " 优先级 MT > ST > H12 > D1-4"),
            ("2,1,3,4,5,6,7,8", " 优先级 ST > MT > H12 > D1-4"),
            ("1,2,7,8,3,4,5,6", " 优先级 MT > ST > D1-4 > H12"),
            ("2,1,7,8,3,4,5,6", " 优先级 ST > MT > D1-4 > H12"),
            ("3,4,1,2,5,6,7,8", " 优先级 H12 > MT > ST > D1-4"),
            ("3,4,2,1,5,6,7,8", " 优先级 H12 > ST > MT > D1-4"),
            ("7,8,1,2,3,4,5,6", " 优先级 H12 > D1-4 > MT > ST"),
            ("8,7,1,2,3,4,5,6", " 优先级 H12 > D1-4 > ST > MT"),
            ("7,8,5,6,1,2,3,4", " 优先级 D1-4 > H12 > MT > ST"),
            ("8,7,5,6,1,2,3,4", " 优先级 D1-4 > H12 > ST > MT"),
            ("7,8,6,5,4,3,2,1", " 优先级 D4-1 > H21 > MT > ST"),
            ("8,7,6,5,4,3,2,1", " 优先级 D4-1 > H21 > ST > MT")
        );
        optionCtrl = new OptionCbx("　[黑洞] 每组点名内分配 1-3 的方式", "P3黑洞_pIdx至prio", cbxItems, "固定");
        form.AddOption(optionCtrl, tableP3);

        hint = @"· 标号说明：
　一组攻击 1-3、二组锁链 1-3、三组禁止 1-2；如果被覆盖会尝试标回来。

　· 若开启自动摇号：
　　会按照上述选用的规则固定为自己摇号并依此播报；
　　被其他人覆盖会重新标回来，请勿在队内开启了指挥标点时开启此选项。

　· 若未开启自动摇号：
　　会按照上述选用的规则指定自身默认接线顺序并播报；
　　被其他人标点后会根据标点覆盖默认接线顺序。";
        optionCtrl = new OptionChk("　[黑洞] 自动摇号（必读提示）", "P3黑洞_b摇号", false, hint);
        optionCtrl.Lbl.ForeColor = Blue;
        form.AddOption(optionCtrl, tableP3);

        cbxItems = new BijectDictionary<string, string>(
            ("黑洞顺", " 面向三个黑洞顺时针"),
            ("黑洞逆", " 面向三个黑洞逆时针"),
            ("Boss顺", " 场外凯夫卡开始顺时针"),
            ("Boss逆", " 场外凯夫卡开始逆时针"),
            ("正北顺", " 正北开始顺时针"),
            ("正北逆", " 正北开始逆时针")
        );
        optionCtrl = new OptionCbx("　[黑洞] 1-3 号分配黑洞的顺序", "P3黑洞_方向排序", cbxItems, "Boss顺");
        form.AddOption(optionCtrl, tableP3);

        cbxItems = new BijectDictionary<string, string>(
            ("0", " 全员接一根"),
            ("1", " 一组 1 号、三组 2 号接两根")
        );
        optionCtrl = new OptionCbx("　[黑洞] 接线方式", "P3黑洞_b双线", cbxItems, "0");
        form.AddOption(optionCtrl, tableP3);

        cbxItems = new BijectDictionary<string, string>(
            ("1", " 顺时针"),
            ("0", " 逆时针")
        );
        optionCtrl = new OptionCbx("　[黑洞] 拉线方向", "P3黑洞_b拉线顺", cbxItems, "1");
        form.AddOption(optionCtrl, tableP3);

        #endregion 配置：P3

        #region 配置：P2

        OptionsTableLayoutPanel tableP2 = form.AddOptionGroup(" P2 ");
        var link = "https://docs.qq.com/doc/DTFBPRkJ0bVFoeGVV";
        var label1 = form.AddLabel("　[遗弃末世]\n　　融合优化 2222 闲人固定 整合解法文档（双击复制链接）\n　　开打前请确认闲人按 TH/D 还是初始扇/钢分组", tableP2);
        label1.ForeColor = Blue;
        label1.DoubleClick += (sender, e) =>
        {
            Clipboard.SetText(link);
            MessageBox.Show("已复制链接。", Info.Name, MessageBoxButtons.OK, MessageBoxIcon.Information);
        };

        cbxItems = new BijectDictionary<string, string>(
            ("0", " 初始扇形左 初始钢铁右"),
            ("1", " TH 左 DPS 右")
        );
        hint = "“闲人” 指的是当前不踩塔的人；指定处理奇数轮分摊/引导扇形、偶数轮超级跳的左右分组方式。\n文档中按照 TH 左 DPS 右固定站位，即站位只和职能相关，省去机制相关的判断；\n但也有现行攻略这里沿用左扇形右钢铁。";
        optionCtrl = new OptionCbx("　[遗弃末世] 闲人处理机制时的左右分组方式", "P2塔_b闲人TH左D右", cbxItems, "1", hint);
        form.AddOption(optionCtrl, tableP2);

        cbxItems = new BijectDictionary<string, string>(
            ("原版", " 原版站位（分摊在两侧）"),
            ("近优", " 近战优化（分摊在前方）")
        );
        hint = "原版站位即为上述文档中站位。";
        optionCtrl = new OptionCbx("　[遗弃末世] 奇数轮的站位", "P2塔_奇数strat", cbxItems, "原版", hint);
        form.AddOption(optionCtrl, tableP2);

        cbxItems = new BijectDictionary<string, string>(
            ("0", " 正北顺时针找第一个初始三角"),
            ("1", " 正北逆时针找第一个初始三角")
        );
        optionCtrl = new OptionCbx("　[异三角] 双 T 处理死刑的方向", "P2_b逆找三角", cbxItems, "1");
        form.AddOption(optionCtrl, tableP2);
        form.AddLabel("　注：为了给死刑留出充足位置，人群并非固定顺/逆，而是优先选择不与 T 相邻的安全区。", tableP2);
        form.AddLabel("", tableP2);
        #endregion 配置：P2

        #region 配置：P1

        OptionsTableLayoutPanel tableP1 = form.AddOptionGroup(" P1 ");

        cbxItems = new BijectDictionary<string, string>(
            ("0", " TH 左 DPS 右"),
            ("1", " 闲人上 击退下")
        );
        optionCtrl = new OptionCbx("　[真假冰火] 分组方式", "P1冰火_b按击退分组", cbxItems, "1");
        form.AddOption(optionCtrl, tableP1);

        cbxItems = new BijectDictionary<string, string>(
            ("1A", " 1A 式"),
            ("1A改", " 1A 改"),
            ("方逆", " 大正方形 逆时针（盗火）"),
            ("方顺", " 大正方形 顺时针（美服）")
        );
        hint = "1A 式：同向箭头外正/外斜，异向箭头内正/内斜\n1A 改：同向箭头内斜/外斜，异向箭头内正/外正";
        optionCtrl = new OptionCbx("　[箭头] 解法", "P1箭头解法", cbxItems, "方逆", hint);
        form.AddOption(optionCtrl, tableP1);

        hint = "固定式：正北开始逆时针 H1 MT H2 ST D2 D4 D1 D3";
        cbxItems = new BijectDictionary<string, string>(
            ("0", " 面向 Boss，TH 左 DPS 右"),
            ("1", " 固定式 场地基准")
        );
        optionCtrl = new OptionCbx("　[真假雷火] 站位", "P1雷火_b固定", cbxItems, "1", hint);
        form.AddOption(optionCtrl, tableP1);

        #endregion 配置：P1

        #region 配置：通用选项

        OptionsTableLayoutPanel tableGeneral = form.AddOptionGroup(" 通用选项 ");

        // 开场自动标点
        cbxItems = new BijectDictionary<string, string>(
            ("2", " 公开标点（北侧顺时针 1A2、半宽 12.0 m 正方形）"),
            ("1", " 本地标点（同上，队里使用其他标点时可以本地覆盖掉）"),
            ("0", " 不开启标点")
        );
        optionCtrl = new OptionCbx("　开场自动应用标准场地标点（防内鬼标点）", "P0场地标点mode", cbxItems, "2");
        form.AddOption(optionCtrl, tableGeneral);
        /*
        // P1 校准小队
        hint = "在……时检查全员站位，如果与设置不符则报错并自动修正。\n魔改站位时不要开。";
        optionCtrl = new OptionChk("开场八方时检查并修正小队", "P1修复小队on", true, hint);
        form.AddOption(optionCtrl, tableGeneral);
        */

        #endregion 配置：通用选项


        #region 配置：文本频道
        OptionsTableLayoutPanel tableChannel = form.AddOptionGroup(" 文本频道 ");
        var cnlItems = new BijectDictionary<string, string>(
            ("", " （禁用）"), ("p", " 小队"), ("e", " 默语"), ("fc", " 部队"),
            ("l1", " 通讯贝1"), ("l2", " 通讯贝2"), ("l3", " 通讯贝3"), ("l4", " 通讯贝4"),
            ("l5", " 通讯贝5"), ("l6", " 通讯贝6"), ("l7", " 通讯贝7"), ("l8", " 通讯贝8"),
            ("cwl1", " 跨服通讯贝1"), ("cwl2", " 跨服通讯贝2"), ("cwl3", " 跨服通讯贝3"), ("cwl4", " 跨服通讯贝4"),
            ("cwl5", " 跨服通讯贝5"), ("cwl6", " 跨服通讯贝6"), ("cwl7", " 跨服通讯贝7"), ("cwl8", " 跨服通讯贝8")
        );
        var cnlPublicItems = cnlItems.ShallowCopy();
        cnlPublicItems.RemoveKey("");
        var cnlDebugItems = cnlItems.ShallowCopy();
        cnlDebugItems.RemoveKey("p");
        var cnlPrivateItems = cnlItems.ShallowCopy();
        cnlPrivateItems.RemoveKey("p");
        cnlPrivateItems.RemoveKey("");

        OptionCbx cnlPublic = new OptionCbx("公共频道", "cnlPublic", cnlPublicItems, "e",
            hint: "本频道用于播报部分机制、示意图、复盘信息等机制相关内容。\n\n默认设为自己可见的默语频道，\n如有需要可设为小队等。\n\n当开启了某个阶段的指挥模式时，相关播报所用的频道会无视此项设置，覆盖为小队频道。");
        OptionCbx cnlPrivate = new OptionCbx("个人频道", "cnlPrivate", cnlPrivateItems, "e",
            hint: "本频道用于发送仅应自己可见的系统提示消息。\n\n本项设置不应选择任何其他人可见的频道。");
        OptionCbx cnlDebug = new OptionCbx("调试频道", "cnlDebug", cnlDebugItems, "",
            hint: "本频道用于发送额外调试信息。\n\n请设置为仅自己可见的频道，或将其关闭。");
        form.AddOption(cnlPublic, tableChannel);
        form.AddOption(cnlPrivate, tableChannel);
        form.AddOption(cnlDebug, tableChannel);

        #endregion 配置：文本频道

        #region 使用须知

        OptionsTableLayoutPanel tableInfo = form.AddOptionGroup(" 使用须知 ");

        form.AddLabel("· 必须在上方正确设置完整的小队列表，否则部分机制无法正常工作。", tableInfo)
            .ForeColor = Color.FromArgb(192, 0, 0);

        form.AddLabel("· 使用前建议查看使用说明，见此绝本触发器分组下的「使用说明」触发器。", tableInfo)
            .ForeColor = Blue;

        form.AddLabel("· 下方部分选项上悬停鼠标可以显示详细说明。", tableInfo)
            .ForeColor = Blue;

        #endregion 使用须知

        #region 配置：队员顺序
        if (BridgeFFXIV.ZoneID == int.Parse("0${env:zone}") && Triggernometry.FFXIV.Entity.GetEntities().Any(e => e.InParty))
        {
            string[] playerDescriptions = { "MT", "ST", "H1", "H2", "D1", "D2", "D3", "D4" };
            var pListPanel = new PartyListPanel(playerDescriptions);
            form.AddPartyGroup(" 队员顺序（拖拽调整） ", pListPanel);
        }
        #endregion 配置：队员顺序

        Application.OpenForms.OfType<GameConfigForm>().ToList().ForEach(f => f.Close());
        form.Run();
    }

    [STAThread]
    public static void Start()
    {
        try
        {
            Application.OpenForms.OfType<GameConfigForm>().ToList().ForEach(f => f.Close());
            Thread staThread = new Thread(new ThreadStart(RunConfigForm));
            staThread.SetApartmentState(ApartmentState.STA);
            staThread.Start();
            staThread.Join();
        }
        catch (Exception ex)
        {
            MessageBox.Show("用户配置表单运行错误：\n" + ex, Info.Name, MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
    }
}

